define("tiny_justify/configuration",["editor_tiny/utils","tiny_justify/commands"],function(Utils,Commands){"use strict";const configure=instanceConfig=>{let menu=instanceConfig.menu;return menu&&menu.format&&menu.format.items&&(menu.format.items=menu.format.items.replace(/\balign(?!\w)/g,Commands.MENU_ALIGN)),{toolbar:Utils.addToolbarButton(instanceConfig.toolbar,"alignment",Commands.COMMAND_ALIGNJUSTIFY,"alignright"),menu:menu,quickbars_selection_toolbar:Utils.addQuickbarsToolbarItem(instanceConfig.quickbars_selection_toolbar,"|","alignleft","aligncenter","alignright",Commands.COMMAND_ALIGNJUSTIFY)}};return{configure}});
